23	
24	USING_YOSYS_NAMESPACE
25	PRIVATE_NAMESPACE_BEGIN
26	
27	struct EquivSimpleConfig : EquivBasicConfig {
28		bool verbose = false;
29		bool short_cones = false;
30		bool group = true;
31		bool parse(const std::vector<std::string>& args, size_t& idx) {
32			if (EquivBasicConfig::parse(args, idx))
33				return true;
34			if (args[idx] == "-v") {
35				verbose = true;
36				return true;
37			}
38			if (args[idx] == "-short") {
39				short_cones = true;
40				return true;
41			}
42			if (args[idx] == "-nogroup") {
43				group = false;
44				return true;
45			}
46			return false;
47		}
48		static std::string help(const char* default_seq) {
49			return EquivBasicConfig::help(default_seq) +
50			"    -v\n"
51			"        verbose output\n"
52			"\n"
53			"    -short\n"
54			"        create shorter input cones that stop at shared nodes. This yields\n"
55			"        simpler SAT problems but sometimes fails to prove equivalence.\n"
56			"\n"
57			"    -nogroup\n"
58			"        disabling grouping of $equiv cells by output wire\n"
59			"\n";
60		}
61	};
62	
63	struct EquivSimpleWorker : public EquivWorker<EquivSimpleConfig>
64	{
65		const vector<Cell*> &equiv_cells;
66		const vector<Cell*> &assume_cells;
67		struct Cone {
68			pool<Cell*> cells;
69			pool<SigBit> bits;
70			void clear() {
71				cells.clear();
72				bits.clear();
73			}
74		};
75	
76		struct DesignModel {
77			const SigMap &sigmap;
78			dict<SigBit, Cell*> &bit2driver;
79		};
80		DesignModel model;
81	
82		pool<pair<Cell*, int>> imported_cells_cache;
83	
84		EquivSimpleWorker(const vector<Cell*> &equiv_cells, const vector<Cell*> &assume_cells, DesignModel model, EquivSimpleConfig cfg) :
85				EquivWorker<EquivSimpleConfig>(equiv_cells.front()->module, &model.sigmap, cfg), equiv_cells(equiv_cells), assume_cells(assume_cells),
86				model(model) {}
87	
88		struct ConeFinder {
89			DesignModel model;
90			// Bits we should also analyze in a later iteration (flop inputs)
91			pool<SigBit> &next_seed;
92			// Cells and bits we've seen so far while traversing
93			Cone& cone;
94			// We're not allowed to traverse past cells and bits in `stop`
95			const Cone& stop;
96			// Input bits are bits that no longer can be traversed
97			// Tracking these is optional
98			pool<SigBit>* input_bits;
99	
100			// Recursively traverses backwards from a cell to find all cells in its input cone
101			// Adds cell to cone.cells, stops at cells in 'stop' set
102			// Returns true if stopped on a stop cell
103			bool find_input_cone(Cell *cell)
104			{
105				if (cone.cells.count(cell))
106					return false;
107	
108				cone.cells.insert(cell);
109	
110				if (stop.cells.count(cell))
111					return true;
112	
113				for (auto &conn : cell->connections())
114					if (yosys_celltypes.cell_input(cell->type, conn.first))
115						for (auto bit : model.sigmap(conn.second)) {
116							if (cell->is_builtin_ff()) {
117								if (!conn.first.in(ID::CLK, ID::C))
118									next_seed.insert(bit);
119							} else
120								find_input_cone(bit);
121						}
122				return false;
123			}
124			void find_input_cone(SigBit bit)
125			{
126				if (cone.bits.count(bit))
127					return;
128	
129				cone.bits.insert(bit);
130	
131				if (stop.bits.count(bit)) {
132					if (input_bits != nullptr) input_bits->insert(bit);
133					return;
134				}
135	
136				if (!model.bit2driver.count(bit))
137					return;
138	
139				// If the input cone of the driver cell reaches a stop bit,
140				// then `bit` is an "input bit"
141				if (find_input_cone(model.bit2driver.at(bit)))
142					if (input_bits != nullptr) input_bits->insert(bit);
143			}
144			void find_input_cone(pool<SigBit> bits)
145			{
146				for (auto bit : bits)
147					find_input_cone(bit);
148			}
149		};
150	
151		// Builds (full or short) input cones from the seeds
152		// Creates full cones (no stops) and optionally short cones (stop at other side's cone)
153		// Updates seed_a/seed_b with next iteration's FF inputs
154		// Returns input bits and cone structures for SAT problem construction
155		std::tuple<pool<SigBit>, Cone, Cone> init_iter(pool<SigBit>& seed_a, pool<SigBit>& seed_b) const
156		{
157			// Empty, never inserted to, to traverse full cones
158			const Cone no_stop;
159			Cone full_cone_a, full_cone_b;
160	
161			// Values of seed_* for the next iteration
162			pool<SigBit> next_seed_a, next_seed_b;
163	
164			{
165				ConeFinder finder_a {model, next_seed_a, full_cone_a, no_stop, nullptr};
166				finder_a.find_input_cone(seed_a);
167	
168				ConeFinder finder_b {model, next_seed_b, full_cone_b, no_stop, nullptr};
169				finder_b.find_input_cone(seed_b);
170			}
171	
172			Cone short_cone_a, short_cone_b;
173			pool<SigBit> input_bits;
174	
175			if (cfg.short_cones)
176			{
177				// Rebuild cones with the knowledge of the full cones.
178				// Avoids stuffing overlaps in input cones into the solver
179				// e.g. for A by using the full B cone as stops
180				next_seed_a.clear();
181				ConeFinder short_finder_a = {model, next_seed_a, short_cone_a, short_cone_b, &input_bits};
182				short_finder_a.find_input_cone(seed_a);
183				next_seed_a.swap(seed_a);
184	
185				next_seed_b.clear();
186				ConeFinder short_finder_b = {model, next_seed_b, short_cone_b, short_cone_a, &input_bits};
187				short_finder_b.find_input_cone(seed_b);
188				next_seed_b.swap(seed_b);
189			}
190			else
191			{
192				short_cone_a = full_cone_a;
193				next_seed_a.swap(seed_a);
194	
195				short_cone_b = full_cone_b;
196				next_seed_b.swap(seed_b);
197			}
198			return std::make_tuple(input_bits, short_cone_a, short_cone_b);
199		}
200	
201		void report_new_cells(const pool<Cell*>& cells, const Cone& cone_a, const Cone& cone_b) const
202		{
203			log("    Adding %d new cells to the problem (%d A, %d B, %d shared).\n",
204						GetSize(cells), GetSize(cone_a.cells), GetSize(cone_b.cells),
205						(GetSize(cone_a.cells) + GetSize(cone_b.cells)) - GetSize(cells));
206			#if 0
207				for (auto cell : short_cells_cone_a)
208					log("      A-side cell: %s\n", cell);
209	
210				for (auto cell : short_cells_cone_b)
211					log("      B-side cell: %s\n", cell);
212			#endif
213		}
214		void report_new_assume_cells(const pool<Cell*>& extra_problem_cells, int old_size, const pool<Cell*>& problem_cells) const
215		{
216			if (cfg.verbose) {
217				log("    Adding %d new cells to check assumptions (and reusing %d).\n",
218					GetSize(problem_cells) - old_size,
219					old_size - (GetSize(problem_cells) - GetSize(extra_problem_cells)));
220			#if 0
221				for (auto cell : extra_problem_cells)
222					log("      cell: %s\n", cell);
223			#endif
224			}
225		}
226	
227		// Ensure the input cones of $assume cells get modelled by the problem
228		pool<Cell*> add_assumes_to_problem(const Cone& cone_a, const Cone& cone_b) const
229		{
230			pool<Cell*> extra_problem_cells;
231			for (auto assume : assume_cells) {
232				pool<SigBit> assume_seed, dummy_next_seed, overlap_bits;
233				assume_seed.insert(model.sigmap(assume->getPort(ID::A)).as_bit());
234				assume_seed.insert(model.sigmap(assume->getPort(ID::EN)).as_bit());
235	
236				for (auto& cone : {cone_a, cone_b}) {
237					Cone assume_cone;
238					ConeFinder{model, dummy_next_seed, assume_cone, cone, &overlap_bits}
239						.find_input_cone(assume_seed);
240					if (GetSize(overlap_bits)) {
241						extra_problem_cells.insert(assume);
242						extra_problem_cells.insert(assume_cone.cells.begin(), assume_cone.cells.end());
243						overlap_bits.clear();
244					}
245					assume_cone.clear();
246					dummy_next_seed.clear();
247				}
248			}
249			return extra_problem_cells;
250		}
251	
252		void prepare_ezsat(int ez_context, SigBit bit_a, SigBit bit_b)
253		{
254			if (satgen.model_undef)
255			{
256				int ez_a = satgen.importSigBit(bit_a, cfg.max_seq+1);
257				int ez_b = satgen.importDefSigBit(bit_b, cfg.max_seq+1);
258				int ez_undef_a = satgen.importUndefSigBit(bit_a, cfg.max_seq+1);
259	
260				ez->assume(ez->XOR(ez_a, ez_b), ez_context);
261				ez->assume(ez->NOT(ez_undef_a), ez_context);
262			}
263			else
264			{
265				int ez_a = satgen.importSigBit(bit_a, cfg.max_seq+1);
266				int ez_b = satgen.importSigBit(bit_b, cfg.max_seq+1);
267				ez->assume(ez->XOR(ez_a, ez_b), ez_context);
268			}
269		}
270		void construct_ezsat(const pool<SigBit>& input_bits, int step)
271		{
272			log("ezsat\n");
273			if (cfg.set_assumes) {
274				log("yep assume\n");
275				if (cfg.verbose && step == cfg.max_seq) {
276					RTLIL::SigSpec assumes_a, assumes_en;
277					satgen.getAssumes(assumes_a, assumes_en, step+1);
278					for (int i = 0; i < GetSize(assumes_a); i++)
279						log("    Import constraint from assume cell: %s when %s (%d).\n", log_signal(assumes_a[i]), log_signal(assumes_en[i]), step);
280				}
281				ez->assume(satgen.importAssumes(step+1));
282			}
283	
284			if (satgen.model_undef) {
285				for (auto bit : input_bits)
286					ez->assume(ez->NOT(satgen.importUndefSigBit(bit, step+1)));
287			}
288	
289			if (cfg.verbose)
290				log("    Problem size at t=%d: %d literals, %d clauses\n", step, ez->numCnfVariables(), ez->numCnfClauses());
291		}
292	
293		bool prove_equiv_cell(Cell* cell)
294		{
295			SigBit bit_a = model.sigmap(cell->getPort(ID::A)).as_bit();
296			SigBit bit_b = model.sigmap(cell->getPort(ID::B)).as_bit();
297			int ez_context = ez->frozen_literal();
298	
299			prepare_ezsat(ez_context, bit_a, bit_b);
300	
301			// Two bits, bit_a, and bit_b, have been marked equivalent in the design
302			// We will be traversing the input cones for each of them
303			// In the first iteration, we will using those as starting points
304			pool<SigBit> seed_a = { bit_a };
305			pool<SigBit> seed_b = { bit_b };
306	
307			if (cfg.verbose) {
308				log("  Trying to prove $equiv cell %s:\n", cell);
309				log("    A = %s, B = %s, Y = %s\n", log_signal(bit_a), log_signal(bit_b), log_signal(cell->getPort(ID::Y)));
310			} else {
311				log("  Trying to prove $equiv for %s:", log_signal(cell->getPort(ID::Y)));
312			}
313	
314			int step = cfg.max_seq;
315			while (1)
316			{
317				// Traverse input cones of seed_a and seed_b, potentially finding new seeds
318				auto [input_bits, cone_a, cone_b] = init_iter(seed_a, seed_b);
319	
320				// Cells to model in SAT solver
321				pool<Cell*> problem_cells;
322				problem_cells.insert(cone_a.cells.begin(), cone_a.cells.end());
323				problem_cells.insert(cone_b.cells.begin(), cone_b.cells.end());
324	
325				if (cfg.verbose)
326					report_new_cells(problem_cells, cone_a, cone_b);
327	
328				if (cfg.set_assumes) {
329					auto extras = add_assumes_to_problem(cone_a, cone_b);
330					if (GetSize(extras)) {
331						auto old_size = GetSize(problem_cells);
332						problem_cells.insert(extras.begin(), extras.end());
333						report_new_assume_cells(extras, old_size, problem_cells);
334					}
335				}
336	
337				for (auto cell : problem_cells) {
338					auto key = pair<Cell*, int>(cell, step+1);
339					if (!imported_cells_cache.count(key) && !satgen.importCell(cell, step+1)) {
340						report_missing_model(cfg.ignore_unknown_cells, cell);
341					}
342					imported_cells_cache.insert(key);
343				}
344	
345				construct_ezsat(input_bits, step);
346	
347				if (!ez->solve(ez_context)) {
348					log("%s", cfg.verbose ? "    Proved equivalence! Marking $equiv cell as proven.\n" : " success!\n");
349					// Replace $equiv cell with a short
350					cell->setPort(ID::B, cell->getPort(ID::A));
351					ez->assume(ez->NOT(ez_context));
352					return true;
353				}
354	
355				if (cfg.verbose)
356					log("    Failed to prove equivalence with sequence length %d.\n", cfg.max_seq - step);
357	
358				if (--step < 0) {
359					if (cfg.verbose)
360						log("    Reached sequence limit.\n");
361					break;
362				}
363	
364				if (seed_a.empty() && seed_b.empty()) {
365					if (cfg.verbose)
366						log("    No nets to continue in previous time step.\n");
367					break;
368				}
369	
370				if (seed_a.empty()) {
371					if (cfg.verbose)
372						log("    No nets on A-side to continue in previous time step.\n");
373					break;
374				}
375	
376				if (seed_b.empty()) {
377					if (cfg.verbose)
378						log("    No nets on B-side to continue in previous time step.\n");
379					break;
380				}
381	
382				if (cfg.verbose) {
383				#if 0
384					log("    Continuing analysis in previous time step with the following nets:\n");
385					for (auto bit : seed_a)
386						log("      A: %s\n", log_signal(bit));
387					for (auto bit : seed_b)
388						log("      B: %s\n", log_signal(bit));
389				#else
390					log("    Continuing analysis in previous time step with %d A- and %d B-nets.\n", GetSize(seed_a), GetSize(seed_b));
391				#endif
392				}
393			}
394	
395			if (!cfg.verbose)
396				log(" failed.\n");
397	
398			ez->assume(ez->NOT(ez_context));
399			return false;
400		}
401	
402		int run()
403		{
404			if (GetSize(equiv_cells) > 1) {
405				SigSpec sig;
406				for (auto c : equiv_cells)
407					sig.append(model.sigmap(c->getPort(ID::Y)));
408				log(" Grouping SAT models for %s:\n", log_signal(sig));
409			}
410	
411			int counter = 0;
412			for (auto c : equiv_cells) {
413				if (prove_equiv_cell(c))
414					counter++;
415			}
416			return counter;
417		}
418	
419	};
420	
421	struct EquivSimplePass : public Pass {
422		EquivSimplePass() : Pass("equiv_simple", "try proving simple $equiv instances") { }
423		void help() override
424		{
425			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
426			log("\n");
427			log("    equiv_simple [options] [selection]\n");
428			log("\n");
429			log("This command tries to prove $equiv cells using a simple direct SAT approach.\n");
430			log("\n");
431			log("%s", EquivSimpleConfig::help("1"));
432			log("\n");
433		}
434		void execute(std::vector<std::string> args, Design *design) override
435		{
436			EquivSimpleConfig cfg {};
437			int success_counter = 0;
438	
439			log_header(design, "Executing EQUIV_SIMPLE pass.\n");
440	
441			size_t argidx;
442			for (argidx = 1; argidx < args.size(); argidx++) {
443				if (cfg.parse(args, argidx))
444					continue;
445				break;
446			}
447			extra_args(args, argidx, design);
448	
449			CellTypes ct;
450			ct.setup_internals();
451			ct.setup_stdcells();
452			ct.setup_internals_ff();
453			ct.setup_stdcells_mem();
454	
455			for (auto module : design->selected_modules())
456			{
457				SigMap sigmap(module);
458				dict<SigBit, Cell*> bit2driver;
459				dict<SigBit, dict<SigBit, Cell*>> unproven_equiv_cells;
460				vector<Cell*> assumes;
461				int unproven_cells_counter = 0;
462	
463				for (auto cell : module->selected_cells()) {
464					if (cell->type == ID($equiv) && cell->getPort(ID::A) != cell->getPort(ID::B)) {
465						auto bit = sigmap(cell->getPort(ID::Y).as_bit());
466						auto bit_group = bit;
467						if (cfg.group && bit_group.wire)
468							bit_group.offset = 0;
469						unproven_equiv_cells[bit_group][bit] = cell;
470						unproven_cells_counter++;
471					} else if (cell->type == ID($assume)) {
472						assumes.push_back(cell);
473					}
474				}
475	
476				if (unproven_equiv_cells.empty())
477					continue;
478	
479				log("Found %d unproven $equiv cells (%d groups) in %s:\n",
480						unproven_cells_counter, GetSize(unproven_equiv_cells), module);
481	
482				for (auto cell : module->cells()) {
483					if (!ct.cell_known(cell->type))
484						continue;
485					for (auto &conn : cell->connections())
486						if (yosys_celltypes.cell_output(cell->type, conn.first))
487							for (auto bit : sigmap(conn.second))
488								bit2driver[bit] = cell;
489				}
490	
491				unproven_equiv_cells.sort();
492				for (auto [_, d] : unproven_equiv_cells)
493				{
494					d.sort();
495	
496					vector<Cell*> cells;
497					for (auto [_, cell] : d)
498						cells.push_back(cell);
499	
500					EquivSimpleWorker::DesignModel model {sigmap, bit2driver};
501					EquivSimpleWorker worker(cells, assumes, model, cfg);
502					success_counter += worker.run();
503				}
504			}
505	
506			log("Proved %d previously unproven $equiv cells.\n", success_counter);
507		}
508	} EquivSimplePass;
509	
510	PRIVATE_NAMESPACE_END
511

